84	    eprintln!("[1/4] Creating LuaState...");
85	    let result = catch_unwind(AssertUnwindSafe(|| {
86	        let mut state = new_state().ok_or("new_state returned None")?;
87	        state.global_mut().parser_hook = Some(parser_hook);
88	
89	        eprintln!("[2/4] Opening standard library...");
90	        open_libs(&mut state).map_err(|e| format!("open_libs failed: {}", render_lua_error(&e)))?;
91	
92	        eprintln!("[3/4] Loading source (parse + compile)...");
