445	/// Push the result of a POSIX-style file operation onto the stack.
446	/// On success pushes `true`; on failure pushes `nil, errmsg, errno`.
447	/// Returns the number of pushed values.
448	///
449	/// C: `LUALIB_API int luaL_fileresult(lua_State *L, int stat, const char *fname)`
450	pub fn file_result(
451	    state: &mut LuaState,
452	    stat: bool,
453	    fname: Option<&[u8]>,
454	) -> Result<usize, LuaError> {
455	    if stat {
456	        // C: lua_pushboolean(L, 1);
457	        state.push(LuaValue::Bool(true));
458	        Ok(1)
459	    } else {
460	        // C: luaL_pushfail(L); = lua_pushnil
461	        state.push(LuaValue::Nil);
462	        // TODO(port): use std::io::Error::last_os_error() for errno-style message.
463	        let errmsg = b"(errno unavailable in Rust port)".to_vec();
464	        if let Some(name) = fname {
465	            let full = [name, b": ".as_slice(), &errmsg].concat();
466	            state.push_bytes(&full)?;
467	        } else {
468	            state.push_bytes(&errmsg)?;
469	        }
470	        // C: lua_pushinteger(L, en);
471	        // TODO(port): push actual errno integer once os-error helpers are available.
472	        state.push(LuaValue::Int(0));
473	        Ok(3)
474	    }
475	}
476	
477	/// Push the result of a process-exit status onto the stack.
478	/// Returns 3 values: success-bool-or-nil, exit-kind string, status code.
479	///
480	/// C: `LUALIB_API int luaL_execresult(lua_State *L, int stat)`
481	// TODO(port): POSIX WIFEXITED / WIFSIGNALED inspection requires cfg(unix).
482	pub fn exec_result(state: &mut LuaState, stat: i32) -> Result<usize, LuaError> {
483	    if stat != 0 {
484	        return file_result(state, false, None);
485	    }
486	    // C: const char *what = "exit";
487	    let what = b"exit".as_slice();
488	    // C: if (*what == 'e' && stat == 0) lua_pushboolean(L, 1);
489	    state.push(LuaValue::Bool(true));
490	    state.push_bytes(what)?;
491	    state.push(LuaValue::Int(stat as i64));
492	    Ok(3)
493	}
