682	pub fn check_number(state: &mut LuaState, arg: i32) -> Result<f64, LuaError> {
683	    // C: int isnum; lua_Number d = lua_tonumberx(L, arg, &isnum);
684	    match state.to_number_x(arg) {
685	        Some(d) => Ok(d),
