    check_next(ls, state, TK_DO)?;
    block(ls, state)?;
    // C: luaK_jumpto(fs, whileinit)
    // TODO(port): lua_code::jump_to(ls.fs.as_mut().unwrap(), whileinit)?;
    check_match(ls, state, TK_END, TK_WHILE, line)?;
