fn error_expected(ls: &LexState, token: TokenKind) -> LuaError {
    // C: luaX_syntaxerror(ls, luaO_pushfstring(ls->L, "%s expected", luaX_token2str(ls, token)));
    // TODO(port): lua_lex::token_to_str(ls, token) for the token name
