}

/// C: static void body(LexState *ls, expdesc *e, int ismethod, int line)
fn body(
    ls: &mut LexState,
    state: &mut LuaState,
    e: &mut ExprDesc,
    ismethod: bool,
    line: i32,
) -> Result<(), LuaError> {
    eprintln!("[DBG] body: ENTER line={} t={}", line, ls.t.token);
    // C: FuncState new_fs; BlockCnt bl; new_fs.f = addprototype(ls); new_fs.f->linedefined = line
    let new_proto = add_prototype(ls, state)?;
    let mut new_fs = FuncState {
        f: new_proto,
        prev: None,
        bl: None,
        pc: 0,
        lasttarget: 0,
        previousline: line,
        nk: 0,
        np: 0,
        nabslineinfo: 0,
        firstlocal: 0,
        firstlabel: 0,
        ndebugvars: 0,
        nactvar: 0,
        nups: 0,
        freereg: 0,
        iwthabs: 0,
        needclose: false,
    };
    new_fs.f.linedefined = line;
    open_func(ls, state, new_fs)?;

    check_next(ls, state, b'(' as TokenKind)?;
    if ismethod {
        // C: new_localvarliteral(ls, "self") — intern "self" and new_localvar
        // TODO(port): intern b"self" via state
        // new_local_var(ls, state, self_str)?;
        adjust_local_vars(ls, state, 1)?;
    }
    eprintln!("[DBG] body: before parlist t={}", ls.t.token);
    parlist(ls, state)?;
    check_next(ls, state, b')' as TokenKind)?;
    eprintln!("[DBG] body: before statlist t={}", ls.t.token);
    statlist(ls, state)?;
    eprintln!("[DBG] body: after statlist t={}", ls.t.token);
    ls.fs.as_mut().unwrap().f.lastlinedefined = ls.linenumber;
    check_match(ls, state, TK_END, TK_FUNCTION, line)?;
    eprintln!("[DBG] body: before codeclosure t={}", ls.t.token);
    codeclosure(ls, state, e)?;
    eprintln!("[DBG] body: before close_func t={}", ls.t.token);
    close_func(ls, state)?;
    eprintln!("[DBG] body: EXIT t={}", ls.t.token);
    Ok(())
}

